    {
      "type": "paragraph",
      "runs": [
        {
          "text": "March 14,\n              2026"
        }
      ]
    },
    {
      "type": "paragraph",
      "runs": [
        {
          "text": "Dear Alex Morgan,\n              "
        }
      ]
    },
    {
      "type": "paragraph",
      "runs": [
        {
          "text": "We are pleased to offer you the position of "
        },
        {
          "text": "Senior Software Engineer",
          "font_weight": "bold"
        },
        {
          "text": " at Cascade Systems Inc. We were impressed by your experience and believe you will be a valuable addition to our engineering team. Below are the details of your offer."
        }
      ]
    },
    {
      "type": "paragraph",
      "runs": [
        {
          "text": "Role: ",
          "font_weight": "bold"
        },
        {
          "text": "Senior Software Engineer\n"
        },
        {
          "text": "Department: ",
          "font_weight": "bold"
        },
        {
          "text": "Platform Engineering\n"
        },
        {
          "text": "Annual Salary: ",
          "font_weight": "bold"
        },
        {
          "text": "$185,\n              000.00\n"
        },
        {
          "text": "Equity Grant: ",
          "font_weight": "bold"
        },
        {
          "text": "15,\n              000 stock options (4-year vesting, 1-year cliff)\n"
        },
        {
          "text": "Start Date: ",
          "font_weight": "bold"
        },
        {
          "text": "April 14,\n              2026\n"
        },
        {
          "text": "Reporting To: ",
          "font_weight": "bold"
        },
        {
          "text": "Elena Vasquez,\n              VP of Engineering"
        }
      ]
    },
    {
      "type": "separator"
    },
    {
      "type": "headline",
      "level": "h2",
      "text": "Benefits"
    },
    {
      "type": "list",
      "variant": "unordered",
      "items": [
        {
          "text": "Comprehensive health,\n                dental,\n                and vision insurance (100% employee, 75% dependents)"
        },
        {
          "text": "401(k) retirement plan with 4% company match"
        },
        {
          "text": "Unlimited paid time off with a 3-week minimum encouraged"
        },
        {
          "text": "$5,\n                000 annual learning and development budget"
        },
        {
          "text": "Flexible remote work policy with quarterly team on-sites"
        },
        {
          "text": "$2,\n                500 home office setup stipend"
        }
      ]
    },
    {
      "type": "separator"
    },
    {
      "type": "paragraph",
      "runs": [
        {
          "text": "This offer is contingent upon successful completion of a background check and is valid for 7 business days from the date of this letter. This letter is not a contract of employment and does not guarantee employment for any specific duration."
        }
      ]
    },
    {
      "type": "separator"
    },
    {
